import{c as e,Q as a,j as i,m as t}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"致尼科洛","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/44-致尼科洛.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/44-致尼科洛.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/upper/44-致尼科洛.md"};function c(l,p,o,_,s,m){return a(),i("div",null,[...p[0]||(p[0]=[t('<h1 id="致尼科洛" tabindex="-1">致尼科洛 <a class="header-anchor" href="#致尼科洛" aria-label="Permalink to &quot;致尼科洛&quot;">​</a></h1><p>致尼科洛 · 马基雅维利 奉自由与和平十人委员会之命 1503年10月24日决议</p><p>尼科洛，你要以最快的速度赶到罗马，带着我们的数份国书，交给多 位极为尊贵的枢机主教，你应该高度重视他们的意见，例如：鲁昂、圣乔 治、圣塞维里诺、阿斯卡尼奥、“锁链中的圣彼得”和圣普拉塞德⑨;你 要以我们的名义将自己介绍给这些枢机主教，并让他们每个人都知道，我 们在最近几天里已经选出了所有的大使。②在我们听到教皇庇护三世去世 的消息时——这使得我们整个城市都陷入悲痛之中，这些大使就已经准备 出发了。尽管他们现在尚未出发，但我们不希望有所疏忽，故而派你前来 表达我们对此事的悲伤之情，以及我们多么希望他们尽快选举出新的教 皇，这是整个基督教世界和意大利的当务之急；我们知道这也是他们的愿 望，我们愿意为此目的竭尽所能帮助他们。还有就是，你在同他们每个人 谈话时，都要按照你认为最恰当的方式把握分寸；而且，要遵照我们至为 尊贵的枢机主教③给你的信息，在你谈论所有这些事情之前，都要征求他 的意见，按照他的命令去执行。你还要带上一份给巴廖尼的军事服役合 同——这份合同是在过去的几天里，教座大人以我们的名义签署的——以 及我们的一条声明，我们希望将这条声明补充到合同中；在所有这些命令</p><p>①鲁昂的枢机主教是乔治 · 德 · 安布瓦兹，鲁昂的大主教；圣乔治(教堂)的枢机主教是拉法埃莱 · 里 亚里奥 · 迪 · 萨沃纳；圣塞维里诺枢机主教是米兰的费代里科 · 圣塞维里诺，他拥有圣泰奥多罗的枢机主 教头衔；阿斯卡尼奥 · 马里亚 · 斯福尔扎是米兰公爵的儿子，拥有圣蒂托和圣莫德斯托 · 马尔蒂里的枢机 主教头衔；朱利亚诺 · 德拉 · 罗韦雷，拥有“锁链中的圣彼得”(教堂)的枢机主教头衔；热那亚的安东 尼奥 · 帕拉维奇尼 · 杰诺维塞，拥有圣普拉塞德枢机主教的头衔。 ——英译本注 ②这些大使是在庇护三世当选为教皇时任命的，他们是：阿雷佐主教科西莫 · 德 · 帕齐、安东尼奥 · 马 利戈奈拉、弗朗切斯科 · 佩皮、马太 · 迪 · 洛伦佐 · 斯特罗齐、托马索 · 保罗 · 安东尼奥 · 索德里 尼。 ——英译本注 ③佛罗伦萨的枢机主教弗朗切斯科 · 索德里尼，沃尔泰拉主教，拥有圣苏珊娜教堂神父的头衔。 ——英 译本注</p><p>中，你一定要遵守下面这条，你首先要同上述我们至为尊贵的枢机主教交 谈，将我们的希望对他说清楚，按照那份声明的内容清楚明白地显示，这 份服役合同的条款规定了我们承担的费用和风险等，因此，在我们需要的 任何时候，都可以根据这份服役合同要求提供数量为400长矛兵的服役。 教座大人会同鲁昂大主教交谈，或者当着你的面，或者私下里，以他们认 为最合适的方式，让这位鲁昂大主教明白我们想要做的事情。就像在信中 已经所表明的那样，这应该不成问题。 一旦我们的上述声明被接受，你就 立刻批准合同，为此，我们授予你全权处置这件事。你要将那份批准生效 的合同文本带回。如果教座大人这么做有困难的话，我们不希望你批准这 份服役合同，而是立刻写信通知我们，然后，我们回信指示你下一步如何 行事。在出现任何困难的情况下，你要做的事情就是，按照我们声明中的 相关条款结束此事；如果有人反对说， 一旦我们拒绝支付，那么国王就得 不到相关服务了，对此你要答复说，如果合同不能在特定的天数内签署， 我们将愿意承认，并且詹保罗也同意，只要我们不履行义务，双方就会回 到旧合同，那样一来，只要一次性付给国王或者詹保罗一笔费用就够了。 同样地，如果鲁昂枢机主教或者詹保罗想制造什么麻烦，并且反对单纯口 头协议的话，你只要向他们提出和承诺说，我们的政府会以某种适当的形 式批准合同，当我们了解大意之后便可应其要求，将文本寄给他们。除此 之外，我们没有别的任务给你，只是你在罗马期间，要每天不间断地同我 们保持通信，将任何值得注意的情报告知。</p><p>执政团致索德里尼枢机主教①</p><p>向在基督天父里至为尊贵的阁下致以最为诚挚的问候；唯主所愿，我 们提名佛罗伦萨公民和国务秘书尼科洛 · 马基雅维利：我们凭着信心派遣</p><p>①英译本未收入，依据贝尔泰利编校本译出。 ——中译者注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>他去向您做一些解释说明。唯主所愿，请求至为尊贵的阁下对我们提名的 这位公民在他所做的一切事情上有坚定的信心。祝一切顺利。 发自市政宫，1503年10月23日 佛罗伦萨正义旗手 马尔切洛</p><p>十人委员会致索德里尼枢机主教①</p><p>至为尊贵的阁下： 我们派遣了我们城邦公民及国务秘书尼科洛 · 马基雅维利前往罗马参 加新教皇的选举，我们在给他的委任状以及所有出使的详细文件资料中布 置了出使任务，他将仔仔细细地对至为尊贵的阁下陈述，我们在命令他如 何谈吐应对的时候已经交代他这么做了；对于这些请阁下按照城邦的需要 给予他指导和建议。</p><p>信件1</p><p>杰出的诸位大人： 昨天晚上，我刚到这里，就给诸位大人写了一封信；②现在，我想告诉 你们，与指示第一部分有关的事情，以及我到了这里后得知的一些情况。 诸位大人应该还记得，在决定詹保罗的合同应谨慎批准之后，你们将 此意向通知了至为尊贵的沃尔泰拉教座大人。教座大人通过你们的信件非 常了解你们的心意，但批准该合同的时间渐渐流逝，教座大人并不知道我 出使此地就是为着这个目的。他给鲁昂枢机主教写了一封信，先寄给你</p><p>①英译本未收入，依据贝尔泰利编校本译出。 ——中译者注 ②第一封写于27日的信已佚失。 ——英译本注</p><p>Opere complete di Niccolò Machiavelli</p><p>们，需要你们亲笔签名。那封信并没有包含别的实质性内容，仅仅包含诸 位大人的声明，就是诸位大人给我的，而我必须处理的那份文件，等等。 当我同他谈起我的任务时，教座大人正在忙这件事，他非常高兴诸位大人 的想法和他一样。他已经放弃了将前面提到的信件送给鲁昂枢机主教签字 这种谈判方式，而是告知后者，还有负责处理此事的主席①:为批准合同 之事，诸位大人派出一名使节专程前来。教座大人随后指示我同鲁昂枢 机主教会谈，但由于后者公务繁忙，我直到今天晚上4点才有机会同他交 谈；鉴于时间和场合，教座大人指示我同鲁昂枢机主教谈些实质的内容， 说我们的诸位大人对国王的利益和对自己利益一样关心，但非常遗憾的 是，他们听说了许多对国王不利的事情，作为国王忠实的朋友，他们觉得 有义务并怀着敬意向国王提及此事，如此，国王才会对这些事给予应有的 重视。于是，我告诉他，据说法国军队已经返回；部署在伦巴第的部队大 部分已经回法国；威尼斯人在罗马涅大兵压境，企图一举拿下那个地方； 诸位大人也非常担心德意志人，无论是他们自己蠢蠢欲动，还是受到别人 的挑拨离间，他们都似乎要来扫荡伦巴第；所有事情都使诸位大人有一种 不祥预兆，因此，我提醒鲁昂教座大人，现在是向意大利增派法国军队的 大好时机，他们应该为此宁愿放弃其他地方的战事，等等。我接着说，我 被派遣到这里是为了批准詹保罗的服役合同，并为此目的接受全权委托。 以任何方式签署的书面合同都不应使佛罗伦萨承担更大的负担，也不应损 害她在同国王陛下业已达成的合约中所享有的权利。鲁昂枢机主教回答 说，感谢诸位大人的建议，他很认真地进行了通盘考虑，而且到这里不是 为了别的目的……谈到詹保罗的服役合同问题，我们将与沃尔泰拉教座大 人一同会谈，一切都将以适当的方式解决。于是，我向我们的枢机主教汇 报了鲁昂枢机主教的两点答复。在有关服役合同的问题上，我们得出结论 说，我们完成了我们这一方的义务，现在要等待他们完成，然后我们再采</p><p>①米兰总督艾蒂安 · 庞彻( Etienne Poncher),巴黎主教。——贝尔泰利编校本注</p><p>取进一步行动。 我相信这封信将通过默伦领主带给你们，此人是由鲁昂枢机主教派往 佛罗伦萨诸位大人处的，然后他会被派往博洛尼亚和费拉拉，最后，被派 往乌尔比诺，为瓦伦蒂诺公爵在罗马涅邦国内受到的损失提出抗议。此次 奥德拉菲进入弗利，这里的每个人都认为是诸位大人的命令，这使得圣乔 治枢机主教为了他的侄子们⑨的缘故怒火中烧，而另一方面，鲁昂枢机主 教也为了瓦伦蒂诺公爵的缘故感到某种程度的气愤。今天早上，特兰斯领 主和主席向沃尔泰拉枢机主教表达了对这件事的不满。后者把我叫住，我 便以罗马涅发生的那些事情为诸位大人进行辩护。正如诸位大人知道的， 我之所以能够这样做是因为我对那些事情了如指掌；然后，为了安抚公 爵，并以赔偿的方式作为某种形式的补救措施，默伦领主或其他人将会被 派去通知他，等等。 公爵目前正在卡斯泰洛，而且比以往任何时候都更加有大展宏图的雄 心壮志。他希望按照他朋友们的意志选出一个新教皇。 教皇庇护三世的正式葬礼今天结束，明天，所有枢机主教都将进入秘 密选举程序；据说，他们要等到巴尔托洛梅奥 · 阿尔维阿诺和奥尔西尼 家族的人撤出罗马才进行选举。二者都在罗马，据说一家有300重骑兵， 而另一家有200,或者有人说更少一点；他们有的是钱，可以装备1000步 兵，但现在还看不到他们有那么多人马。 詹保罗现驻扎在乡镇，他的手下说他有100重骑兵，并已经从他的服 役合同中收到5000达克特，还有3000达克特作为步兵军饷，不过目前还 没有看到一个人。我还没有能够同他交谈。除了我们的枢机主教，我很少 同其他人说过话，因此，我还无法按照自己的愿望为你们提供此地的信 息；但我会不断努力，竭尽全力履行我的职责。 我得到的关于法国军队的消息是，他们已经到了圣杰尔马诺，向孔萨</p><p>①圣乔治枢机主教的侄子们指弗利伯爵吉罗拉莫 · 里亚里奥和卡泰丽娜 · 斯福尔扎的儿子们，他们被瓦 伦蒂诺公爵抢占了弗利的领地。 ——中译者注</p><p>Opere complete di Niccolo Machiavelli</p><p>尔沃①发起挑战，被他拒绝了。法国军队觉得没有能力攻克那个地方，他 们决定返回，并试图在其他地方找到一条通道；据说，他们现在到了科尔 沃桥，要朝加埃塔方向前进，以通过加里利亚诺河。</p>',22)])])}const h=e(r,[["render",c]]);export{d as __pageData,h as default};
